UPDATE ctgb_products SET gebruiksvoorschriften = '[{"gewas": "Kamerplanten", "locatie": "Binnen", "toepassingsmethode": "Poederen, Voor uitplanten", "maxToepassingen": 1, "opmerkingen": ["Dosering middel per toepassing: de stekken met de\nonderste 1-2 cm in het poeder dippen.\nkamerplanten (opkweek plantmateriaal)\n\nDe dosering (hoeveelheid middel per stek) wordt bepaald door dikte en structuur van de stek. De ondereindjes van de onbewortelde stekken worden in water bevochtigd, waarna de stekken met de onderste 1-2 cm in het poeder worden gedoopt. Het overtollige poeder wordt verwijderd door voorzichtig afkloppen, waarna de stekken geplant worden."], "wCodes": ["W1"]}, {"gewas": "Sierbeplanting (planten in de vollegrond)", "locatie": "Binnen", "toepassingsmethode": "Poederen, Voor uitplanten", "maxToepassingen": 1, "opmerkingen": ["Dosering middel per toepassing: de stekken met de\nonderste 1-2 cm in het poeder dippen.\nSierplanten (opkweek plantmateriaal)\n\nDe dosering (hoeveelheid middel per stek) wordt bepaald door dikte en structuur van de stek. De ondereindjes van de onbewortelde stekken worden in water bevochtigd, waarna de stekken met de onderste 1-2 cm in het poeder worden gedoopt. Het overtollige poeder wordt verwijderd door voorzichtig afkloppen, waarna de stekken geplant worden."], "wCodes": ["W1"]}, {"gewas": "Aronskelk, Calla, Cyclaam, Dahlia, Freesia, Nerine, Lelie, Ranonkel, Zantedeschia, Overige voorjaarsgeplante bloembollen en -knollen, Gladiool, Amaryllis, Anemoon, Blauwe druifjes, Hyacint, Iris, Krokus, Narcis, Sierui, Sneeuwroem, Tulp, Overige najaarsgeplante bloembollen en -knollen, Overige bolbloemen en knolbloemen, Zantedeschia/Calla/Aronskelk, Phalaenopsis, Ficus, Overige potplanten, Roos, Orchidee, Lepelplant, Chrysant, Skimmia, Prunus, Ilex, Sering, Chinees klokje, Eustoma, Alstroemeria, Overige snijbloemen, Anjer, Pioenroos, Asparagus, Ruscus, Maranta, Polystichum, Magnolia, Overige laanbomen, Els, Iep, Plantaan, Acasia, Christusdoorn, P